const item = $('Get Tracked Pages').item.json;
const response = $input.item.json;

// Extract text content (strip HTML tags for comparison)
const body = (typeof response === 'string' ? response : (response.data || response.body || '')).toString();
const textContent = body.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 50000);

// Simple hash (use first 64 chars of base64 encoded text)
const encoder = new TextEncoder();
const hashBuffer = await crypto.subtle.digest('SHA-256', encoder.encode(textContent));
const hashArray = Array.from(new Uint8Array(hashBuffer));
const newHash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

const changed = item.prev_hash !== newHash;

// Classify drift direction heuristically
let driftDirection = 'gradual';
let severity = 'low';
if (changed) {
  const prevLen = textContent.length;
  // Large changes on homepage/pricing = deliberate
  if (item.page_type === 'homepage' || item.page_type === 'pricing') {
    severity = 'high';
    driftDirection = 'deliberate';
  } else if (item.page_type === 'comparison') {
    severity = 'medium';
    driftDirection = 'deliberate';
  } else {
    severity = 'low';
    driftDirection = 'gradual';
  }
}

return [{
  json: {
    user_id: item.user_id,
    page_url: item.page_url,
    page_type: item.page_type,
    page_title: item.page_title,
    snapshot_text: textContent.substring(0, 10000),
    snapshot_hash: newHash,
    prev_hash: item.prev_hash,
    changed: changed,
    drift_direction: driftDirection,
    severity: severity
  }
}];
